// 00 환경설정 - N8Lient 실행 Payload 기준
// 서버 간 호출과 브라우저 직접 업로드 호출을 모두 지원한다.
// 1) 서버 간 호출: X-N8N-TOKEN 검증 후 payload.settings를 그대로 사용한다.
// 2) 브라우저 직접 업로드: submissionId + uploadToken을 N8Lient verify API로 검증하고 canonical payload를 사용한다.
// n8n은 개인 설정과 회사 공용 설정을 직접 병합하지 않는다.
// 엔팔라이언트가 검증/병합 완료한 settings만 최종 실행 설정값으로 사용한다.
// Google Drive/Gmail 노드는 n8n에 등록된 공용 Google 계정 Credential을 사용한다.

const item = $input.first();
const rawJson = item.json || {};

const parseJsonIfPossible = (value) => {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  if (!trimmed) return value;
  try { return JSON.parse(trimmed); } catch (e) { return value; }
};

const normalizeHeaders = (headers = {}) => {
  const normalized = {};
  for (const [key, value] of Object.entries(headers || {})) {
    normalized[String(key).toLowerCase()] = value;
  }
  return normalized;
};

let body = parseJsonIfPossible(rawJson.body);
if (!body || typeof body !== 'object' || Array.isArray(body)) {
  body = {};
}

// multipart/form-data에서는 payload가 문자열 필드로 들어올 수 있다.
const embeddedPayload = parseJsonIfPossible(body.payload || rawJson.payload);
const payloadCandidate =
  embeddedPayload && typeof embeddedPayload === 'object' && !Array.isArray(embeddedPayload)
    ? embeddedPayload
    : (Object.keys(body).length ? body : rawJson);

const headers = normalizeHeaders(rawJson.headers || {});
const expectedToken = $env.N8N_SERVER_MAIN_TOKEN || $env.N8N_WEBHOOK_TOKEN || '';
const incomingToken = headers['x-n8n-token'] || '';

const submissionId =
  payloadCandidate.submissionId ||
  body.submissionId ||
  rawJson.submissionId ||
  '';

const uploadToken =
  payloadCandidate.uploadToken ||
  body.uploadToken ||
  rawJson.uploadToken ||
  '';

let payload = null;
let authMode = 'unknown';

// 1) 서버 간 호출: 기존 execute API → n8n 호출 경로
if (expectedToken && incomingToken && incomingToken === expectedToken) {
  payload = payloadCandidate;
  authMode = 'server-token';
} else if (!expectedToken && !uploadToken) {
  // 개발/테스트 환경에서 n8n 토큰을 쓰지 않는 경우에만 기존 payload를 허용한다.
  payload = payloadCandidate;
  authMode = 'no-server-token-dev';
} else if (uploadToken && submissionId) {
  // 2) 브라우저 직접 업로드: 1회성 uploadToken 검증
  const baseUrl = String(
    payloadCandidate.verifyBaseUrl ||
    payloadCandidate.n8lientBaseUrl ||
    $env.N8LIENT_BASE_URL ||
    $env.N8LIENT_APP_BASE_URL ||
    ''
  ).replace(/\/+$/, '');

  const verifyUrl =
    payloadCandidate.verifyUrl ||
    (baseUrl ? `${baseUrl}/api/automation/verify-upload-token` : '');

  if (!verifyUrl) {
    throw new Error('N8Lient 업로드 토큰 검증 오류: verify-upload-token URL을 만들 수 없습니다. n8n 환경변수 N8LIENT_BASE_URL을 설정하세요.');
  }

  const verifyResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: verifyUrl,
    body: {
      submissionId,
      uploadToken,
    },
    json: true,
    timeout: 300000,
  });

  if (!verifyResponse || verifyResponse.valid !== true || !verifyResponse.payload) {
    throw new Error(`N8Lient Upload Token Verification Failed: ${verifyResponse?.error || 'Unknown'}`);
  }

  payload = verifyResponse.payload;
  authMode = 'upload-token';
} else {
  throw new Error('N8Lient Webhook 인증 실패: X-N8N-TOKEN 또는 유효한 uploadToken이 필요합니다.');
}

const settings = payload.settings || {};
const input = payload.input || {};

if (!payload.submissionId) {
  throw new Error('N8Lient payload 오류: submissionId가 없습니다.');
}

if (!payload.callbackUrl) {
  throw new Error('N8Lient payload 오류: callbackUrl이 없습니다.');
}

if (!settings.mdFolderId) {
  throw new Error('N8Lient settings 오류: settings.mdFolderId가 없습니다.');
}

if (!settings.originalFileFolderId) {
  throw new Error('N8Lient settings 오류: settings.originalFileFolderId가 없습니다.');
}

const config = {
  workflowName: "N8Lient 아이디어 캐처",
  workflowKey: payload.workflowKey || 'idea-catcher',
  automationId: payload.automationId || '',
  submissionId: payload.submissionId,
  clientId: payload.clientId || '',
  uid: payload.uid || '',
  callbackUrl: payload.callbackUrl,
  requestedAt: payload.requestedAt || new Date().toISOString(),

  // Auth
  authMode,

  // Gemini
  geminiModel: settings.geminiModel || 'gemini-2.5-flash',

  // N8Lient에서 병합 완료된 최종 settings만 사용한다.
  originalFileFolderId: settings.originalFileFolderId,
  mdFolderId: settings.mdFolderId,
  reportEmailTo: settings.reportEmailTo || '',

  // File naming
  audioPrefix: settings.audioPrefix || 'idea_audio',
  mdPrefix: settings.mdPrefix || 'idea_card',

  // 프롬프트: AI는 title/paragraphs/keywords만 JSON으로 반환한다.
  // MD 구조와 출처는 n8n 코드가 고정 생성한다.
  // 긴 음성 글쓰기를 과도하게 요약하지 않고, 말의 흐름을 살리는 방향이다.
  prompt: `너는 한국어 음성 글쓰기를 정리하는 보조 작가다.

사용자는 음성으로 글을 쓴다.
음성에는 "음", "어", 반복, 중단된 말, 되돌아간 설명, 주제 전환이 있을 수 있다.

목표:
끊긴 말과 생각의 공백은 말한 내용의 범위 안에서 자연스럽게 이어 문장화한다.
사용자가 말한 흐름, 논리, 예시, 감정의 결을 최대한 보존한다.
중언부언, 추임새, 반복, 말꼬리만 걷어내고 읽기 좋은 글로 정리한다.
AI가 임의로 검열하거나 절반으로 줄이지 않는다.
임의로 짧게 압축하지 않는다.

제목 규칙:
- title은 평범한 요약 제목으로 만들지 않는다.
- title은 실제 발화 속에서 나온 인상적인 표현, 핵심 문장, 힘 있는 워딩을 골라 만든다.
- 사용자가 직접 제목을 말하지 않았더라도, 말한 내용 안에서 가장 제목다운 표현을 찾아 25자 이내로 다듬는다.
- "아이디어 카드노트", "음성 메모", "생각 정리", "내용 요약", "아이디어 노트" 같은 일반 제목은 쓰지 않는다.
- 사용자가 말하지 않은 멋있는 표현을 새로 창작하지 않는다.
- 실제 워딩을 살리되 제목으로 읽히도록 조사나 어미 정도만 자연스럽게 다듬는다.

본문 규칙:
- paragraphs는 본문 문단 배열이다.
- 각 문단은 자연스러운 글 문장으로 작성한다.
- 사용자가 말한 순서와 흐름을 가능한 한 유지한다.
- 여러 생각이 이어지면 문단을 나누어 정리한다.
- 중언부언은 제거하되, 생각의 전개와 설명은 지나치게 줄이지 않는다.
- 사용자가 말하지 않은 사실, 사례, 결론을 새로 만들지 않는다.

출력 규칙:
- JSON만 반환한다.
- 마크다운, 코드블록, 설명문은 쓰지 않는다.
- keywords는 3~7개 배열로 만든다.

반환 형식:
{"title":"","paragraphs":[""],"keywords":[""]}`
};

return [{
  json: {
    ...payload,
    input,
    settings,
    _payload: payload,
    _config: config,
  },
  binary: item.binary,
}];

// 01 입력 정리 - N8Lient payload 정규화
// 지원 입력:
// 1) input.fileUrl 기반 파일 다운로드
// 2) Webhook multipart/binary 직접 입력
// 3) input.text만 있는 경우 원본 텍스트 파일로 보관 후 Gemini 텍스트 처리

const item = $input.first();
const config = item.json._config || {};
const payload = item.json._payload || item.json || {};
const input = payload.input || {};
const binary = item.binary || {};

const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const yyyy = now.getFullYear();
const MM = pad(now.getMonth() + 1);
const dd = pad(now.getDate());
const hh = pad(now.getHours());
const mm = pad(now.getMinutes());
const ss = pad(now.getSeconds());

const dateText = `${yyyy}-${MM}-${dd} ${hh}:${mm}`;
const stamp = `${yyyy}${MM}${dd}_${hh}${mm}${ss}`;

const sourceTitle = String(input.title || payload.title || '').trim();
const sourceContent = String(input.text || input.content || payload.text || '').trim();
const submissionId = String(payload.submissionId || config.submissionId || '').trim();

const getExt = (fileName, mimeType, fallback = 'webm') => {
  const name = String(fileName || '').trim();
  if (name.includes('.')) return name.split('.').pop().toLowerCase();
  const mime = String(mimeType || '').toLowerCase();
  if (mime.includes('mpeg')) return 'mp3';
  if (mime.includes('mp4')) return 'mp4';
  if (mime.includes('webm')) return 'webm';
  if (mime.includes('wav')) return 'wav';
  if (mime.includes('ogg')) return 'ogg';
  if (mime.includes('plain')) return 'txt';
  if (mime.includes('markdown')) return 'md';
  return fallback;
};

let fileBuffer = null;
let fileMeta = null;
let sourceMode = 'unknown';

const binaryKeys = Object.keys(binary);
const existingBinaryKey =
  binaryKeys.find((key) => (binary[key].mimeType || '').startsWith('audio/')) ||
  binaryKeys.find((key) => key.startsWith('file_')) ||
  binaryKeys[0];

if (existingBinaryKey) {
  fileMeta = binary[existingBinaryKey];
  fileBuffer = await this.helpers.getBinaryDataBuffer(0, existingBinaryKey);
  sourceMode = 'binary';
} else if (input.fileUrl) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: input.fileUrl,
    uri: input.fileUrl,
    encoding: null,
    json: false,
    returnFullResponse: true,
    resolveWithFullResponse: true,
    simple: true,
  });

  const body = response.body ?? response;
  fileBuffer = Buffer.isBuffer(body) ? body : Buffer.from(body);
  const headers = response.headers || {};
  fileMeta = {
    fileName: input.fileName || `n8lient_input_${stamp}`,
    mimeType: input.mimeType || headers['content-type'] || 'application/octet-stream',
    fileSize: fileBuffer.length,
  };
  sourceMode = 'fileUrl';
} else if (sourceContent) {
  fileBuffer = Buffer.from(sourceContent, 'utf8');
  fileMeta = {
    fileName: input.fileName || `n8lient_text_${stamp}.txt`,
    mimeType: 'text/plain',
    fileSize: fileBuffer.length,
  };
  sourceMode = 'text';
} else {
  throw new Error('N8Lient 입력 오류: input.fileUrl, binary 파일 또는 input.text 중 하나가 필요합니다.');
}

const originalName = fileMeta.fileName || `n8lient_input_${stamp}`;
const mimeType = fileMeta.mimeType || input.mimeType || 'application/octet-stream';
const extFromName = getExt(originalName, mimeType, sourceMode === 'text' ? 'txt' : 'webm');
const safeOriginalName = `${config.audioPrefix || 'idea_audio'}_${stamp}.${extFromName}`;
const isTextOnly = sourceMode === 'text' || String(mimeType).startsWith('text/');

return [{
  json: {
    _config: config,
    sourceTitle,
    sourceContent,
    submissionId,
    clientId: payload.clientId || config.clientId || '',
    uid: payload.uid || config.uid || '',
    workflowKey: payload.workflowKey || config.workflowKey || 'idea-catcher',
    automationId: payload.automationId || config.automationId || '',
    callbackUrl: payload.callbackUrl || config.callbackUrl || '',
    requestedAt: payload.requestedAt || config.requestedAt || '',
    receivedAt: dateText,
    stamp,
    inputMode: sourceMode === 'text' ? 'N8Lient 텍스트 입력' : 'N8Lient 파일 입력',
    inputFileUrl: input.fileUrl || '',
    originalAudioFileName: safeOriginalName,
    originalAudioMimeType: mimeType,
    originalAudioSize: fileMeta.fileSize || fileBuffer.length,
    audioBase64: isTextOnly ? '' : fileBuffer.toString('base64'),
    isTextOnly,
  },
  binary: {
    sourceAudio: {
      data: fileBuffer.toString('base64'),
      mimeType,
      fileName: safeOriginalName,
      fileExtension: extFromName,
    },
  },
}];

// Google Drive 저장 결과 + 01 입력 정리 결과를 결합해 Gemini 요청 JSON 생성
const drive = $input.first().json;
const prep = $items('01 입력 정리')[0].json;

const sourceFileId = drive.id || drive.fileId || '';
const audioDriveLink = drive.webViewLink || (sourceFileId ? `https://drive.google.com/file/d/${sourceFileId}/view?usp=drivesdk` : '');

const config = prep._config || {};

const sourceText = [
  prep.sourceTitle ? `사용자 입력 제목: ${prep.sourceTitle}` : '',
  prep.sourceContent ? `사용자 입력 내용: ${prep.sourceContent}` : '',
  `입력방식: ${prep.inputMode || 'N8Lient 입력'}`,
  prep.submissionId ? `submissionId: ${prep.submissionId}` : '',
  prep.clientId ? `clientId: ${prep.clientId}` : '',
  prep.uid ? `uid: ${prep.uid}` : '',
  `워크플로우명: ${config.workflowName || 'N8Lient 아이디어 캐처'}`,
  `원본 파일명: ${prep.originalAudioFileName}`,
  audioDriveLink ? `원본 파일 링크: ${audioDriveLink}` : '',
  prep.requestedAt ? `요청일시: ${prep.requestedAt}` : '',
  `생성일시: ${prep.receivedAt}`,
].filter(Boolean).join('\n');

const instruction = `${config.prompt}\n\n참고 정보:\n${sourceText}`;

const parts = [{ text: instruction }];
if (prep.audioBase64 && !prep.isTextOnly) {
  parts.push({
    inlineData: {
      mimeType: prep.originalAudioMimeType || 'audio/webm',
      data: prep.audioBase64,
    },
  });
}

const geminiPayload = {
  contents: [
    {
      role: 'user',
      parts,
    },
  ],
  generationConfig: {
    temperature: 0.25,
    topP: 0.85,
    maxOutputTokens: 15000,
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'OBJECT',
      properties: {
        title: { type: 'STRING' },
        paragraphs: {
          type: 'ARRAY',
          items: { type: 'STRING' },
        },
        keywords: {
          type: 'ARRAY',
          items: { type: 'STRING' },
        },
      },
      required: ['title', 'paragraphs', 'keywords'],
    },
  },
};

return [{
  json: {
    ...prep,
    audioFileId: sourceFileId,
    audioDriveLink,
    geminiPayload,
    // Gemini API Key는 HTTP Request 노드의 Google Gemini(PaLM) Credential이 주입한다.
    geminiUrl: `https://generativelanguage.googleapis.com/v1beta/models/${config.geminiModel}:generateContent`,
  },
}];

// Gemini 응답에서 title/paragraphs/keywords를 추출하고, n8n에서 표준 Markdown을 1회만 생성한다.
// 중요: JSON 파싱이 실패하면 억지로 MD를 만들지 않고 오류 처리한다.
// 원본 파일은 이미 Drive에 저장되어 있으므로 공통 오류 리포터로 확인 후 재처리한다.
const res = $input.first().json;
const meta = $items('03 Gemini 요청 구성')[0].json;
const config = meta._config || {};

const parts = res.candidates?.[0]?.content?.parts || [];
let raw = parts.map((p) => p.text || '').join('\n').trim();

if (!raw) {
  throw new Error('Gemini 응답에서 내용을 찾지 못했습니다. 원본 파일은 Drive에 저장되어 있으므로 재처리할 수 있습니다.');
}

const stripCodeFence = (text) => String(text)
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

const normalizeKeywords = (value) => {
  if (Array.isArray(value)) return value.map((v) => String(v).trim()).filter(Boolean).slice(0, 7);
  if (typeof value === 'string') return value.split(/[,\n]/).map((v) => v.replace(/^[-*]\s*/, '').trim()).filter(Boolean).slice(0, 7);
  return [];
};

const cleanText = (text) => String(text || '')
  .replace(/##\s*제목/gi, '')
  .replace(/##\s*내용/gi, '')
  .replace(/##\s*키워드(?: \(선택\))?/gi, '')
  .replace(/##\s*출처/gi, '')
  .replace(/원본 파일명\s*[:：].*/gi, '')
  .replace(/원본 파일 링크\s*[:：].*/gi, '')
  .replace(/생성일시\s*[:：].*/gi, '')
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed = null;
try {
  parsed = JSON.parse(stripCodeFence(raw));
} catch (e) {
  throw new Error(`Gemini 응답 JSON 파싱 실패. 불완전한 MD를 생성하지 않고 중단합니다. 원본 파일 링크: ${meta.audioDriveLink || ''}\n\n원본 응답 앞부분:\n${raw.slice(0, 1200)}`);
}

const normalizeParagraphs = (value) => {
  if (Array.isArray(value)) {
    return value.map((p) => cleanText(p)).filter(Boolean);
  }

  // 구버전 응답 호환: content 문자열이 온 경우 문단으로 변환한다.
  if (typeof value === 'string') {
    const cleaned = cleanText(value);
    return cleaned
      .split(/\n{2,}/)
      .map((p) => p.trim())
      .filter(Boolean);
  }

  return [];
};

let paragraphs = normalizeParagraphs(parsed?.paragraphs);
if (paragraphs.length === 0 && parsed?.content) {
  paragraphs = normalizeParagraphs(parsed.content);
}

if (paragraphs.length === 0) {
  throw new Error(`Gemini 응답에 본문 paragraphs가 없습니다. 원본 파일 링크: ${meta.audioDriveLink || ''}`);
}

const genericTitlePatterns = [
  /^아이디어\s*카드노트$/i,
  /^아이디어\s*노트$/i,
  /^음성\s*메모$/i,
  /^음성\s*메모\s*정리$/i,
  /^생각\s*정리$/i,
  /^내용\s*요약$/i,
  /^메모\s*정리$/i,
  /^제목\s*없음$/i,
];

const sanitizeTitle = (s) => String(s || '')
  .replace(/[\\/:*?"<>|#\[\]\n\r\t]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const isGenericTitle = (title) => {
  const t = sanitizeTitle(title);
  return !t || genericTitlePatterns.some((re) => re.test(t));
};

const deriveTitleFromParagraphs = (paragraphList) => {
  const full = paragraphList.join(' ').replace(/\s+/g, ' ').trim();
  if (!full) return '';

  // 실제 발화 흐름에서 제목다운 문장을 우선 선택한다.
  const roughSentences = full
    .split(/(?<=[.!?])\s+|[。！？]\s*|\n+/)
    .map((s) => sanitizeTitle(s))
    .filter(Boolean);

  const preferred = roughSentences.find((s) =>
    s.length >= 8 && s.length <= 80 && /(해야|필요|중요|싫|좋|문제|핵심|방법|생각|글|작가|AI|잡아|놓치)/.test(s)
  ) || roughSentences.find((s) => s.length >= 8 && s.length <= 80) || full;

  return sanitizeTitle(preferred).slice(0, 25).trim();
};

let noteTitle = sanitizeTitle(parsed?.title);
if (isGenericTitle(noteTitle)) {
  const sourceTitle = sanitizeTitle(meta.sourceTitle);
  noteTitle = !isGenericTitle(sourceTitle) ? sourceTitle.slice(0, 25) : deriveTitleFromParagraphs(paragraphs);
}

if (!noteTitle) {
  throw new Error(`제목을 생성하지 못했습니다. 원본 파일 링크: ${meta.audioDriveLink || ''}`);
}

const content = paragraphs.join('\n\n');
let keywords = normalizeKeywords(parsed?.keywords);
if (keywords.length === 0) keywords = ['음성 글쓰기', '아이디어 정리'];

const keywordMd = keywords.map((k) => `- ${k}`).join('\n');
const workflowName = config.workflowName || "JANG'S 아이디어 캐처";

const md = `## 제목

${noteTitle}

